static void flushed_printf(const char* format, ...) {
    va_list args;
    va_start(args, format);
    vprintf(format, args);
    va_end(args);
    fflush(stdout);
}

static void show_progress_init(int length) {
    flushed_printf("[");
    for (int i = 0; i < length; i++)
        flushed_printf(" ");
    flushed_printf("]");
    for (int i = 0; i <= length; i++)
        flushed_printf("\b");
}

static void show_progress_step(int domove, char newchar) {
    flushed_printf("%c", newchar);
    if (!domove)
        flushed_printf("\b");
}

static void show_progress_done(void) {
    flushed_printf("\n");
}

template <int TotalBenchIterations, typename Func>
static double benchmark_repeat(Func&& func) {
    double best = 0.0;
    for (int i = 0; i < TotalBenchIterations; ++i) {
        const double value = func();
        if (i == 0 || value < best)
            best = value;
    }
    return best;
}

template <typename LaunchFunc>
static double time_cuda_kernel(LaunchFunc&& launch, bool use_os_timer) {
    if (use_os_timer) {
        auto ts_start = std::chrono::high_resolution_clock::now();
        launch();
        CUDA_SAFE_CALL(cudaPeekAtLastError());
        CUDA_SAFE_CALL(cudaDeviceSynchronize());
        auto ts_end = std::chrono::high_resolution_clock::now();
        return std::chrono::duration<double, std::milli>(ts_end - ts_start).count();
    } else {
        cudaEvent_t ev_start, ev_stop;
        CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
        CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
        CUDA_SAFE_CALL(cudaEventRecord(ev_start, 0));
        launch();
        CUDA_SAFE_CALL(cudaPeekAtLastError());
        CUDA_SAFE_CALL(cudaEventRecord(ev_stop, 0));
        CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
        float elapsed_ms = 0.0f;
        CUDA_SAFE_CALL(cudaEventElapsedTime(&elapsed_ms, ev_start, ev_stop));
        CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
        CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
        return static_cast<double>(elapsed_ms);
    }
}

template <typename T>
struct DeviceOps;

template <>
struct DeviceOps<int> {
    __device__ __forceinline__ static int add(int a, int b) { return a + b; }
    __device__ __forceinline__ static int mul(int a, int b) { return a * b; }
    __device__ __forceinline__ static int zero() { return 0; }
    __device__ __forceinline__ static int neg_one() { return -1; }
    __device__ __forceinline__ static bool equal(int a, int b) { return a == b; }
};

template <>
struct DeviceOps<float> {
    __device__ __forceinline__ static float add(float a, float b) { return a + b; }
    __device__ __forceinline__ static float mul(float a, float b) { return a * b; }
    __device__ __forceinline__ static float zero() { return 0.0f; }
    __device__ __forceinline__ static float neg_one() { return -1.0f; }
    __device__ __forceinline__ static bool equal(float a, float b) { return a == b; }
};

template <>
struct DeviceOps<double> {
    __device__ __forceinline__ static double add(double a, double b) { return a + b; }
    __device__ __forceinline__ static double mul(double a, double b) { return a * b; }
    __device__ __forceinline__ static double zero() { return 0.0; }
    __device__ __forceinline__ static double neg_one() { return -1.0; }
    __device__ __forceinline__ static bool equal(double a, double b) { return a == b; }
};

template <>
struct DeviceOps<__half2> {
    __device__ __forceinline__ static __half2 add(__half2 a, __half2 b) { return __hadd2(a, b); }
    __device__ __forceinline__ static __half2 mul(__half2 a, __half2 b) { return __hmul2(a, b); }
    __device__ __forceinline__ static __half2 zero() { return __float2half2_rn(0.0f); }
    __device__ __forceinline__ static __half2 neg_one() { return __float2half2_rn(-1.0f); }
    __device__ __forceinline__ static bool equal(__half2 a, __half2 b) {
        return __heq(__low2half(a), __low2half(b)) && __heq(__high2half(a), __high2half(b));
    }
};

template <typename T, bool BLOCK_STRIDED, int COMPUTE_ITERATIONS, int ELEMENTS_PER_THREAD, int FUSION_DEGREE>
__global__ void benchmark_kernel(T seed, T* g_data) {
    const unsigned int blockSize = blockDim.x;
    int stride;
    int idx;

    if (BLOCK_STRIDED) {
        stride = static_cast<int>(blockSize);
        idx = static_cast<int>(blockIdx.x * blockSize * ELEMENTS_PER_THREAD + threadIdx.x);
    } else {
        const int grid_size = static_cast<int>(blockDim.x * gridDim.x);
        stride = grid_size;
        idx = static_cast<int>(blockIdx.x * blockDim.x + threadIdx.x);
    }

    const int big_stride = static_cast<int>(gridDim.x * blockDim.x * ELEMENTS_PER_THREAD);

    T tmps[ELEMENTS_PER_THREAD];
    for (int k = 0; k < FUSION_DEGREE; k++) {
#pragma unroll
        for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
            tmps[j] = g_data[idx + j * stride + k * big_stride];
#pragma unroll
            for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
                tmps[j] = DeviceOps<T>::add(DeviceOps<T>::mul(tmps[j], tmps[j]), seed);
            }
        }

        T sum = DeviceOps<T>::zero();
#pragma unroll
        for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2)
            sum = DeviceOps<T>::add(sum, DeviceOps<T>::mul(tmps[j], tmps[j + 1]));

        if (DeviceOps<T>::equal(sum, DeviceOps<T>::neg_one()))
            g_data[idx + k * big_stride] = sum;
    }
}

