static void runbench_warmup(void* cbuffer, long size, size_t workgroupsize, bool block_strided) {
    const long reduced_grid_size = size / 256;
    const int threads = static_cast<int>(workgroupsize);
    const int blocks = static_cast<int>(reduced_grid_size / static_cast<long>(workgroupsize));
    const short seed = 1;

    if (block_strided) {
        benchmark_kernel<short, true, 0, 1, 1><<<blocks, threads>>>(seed, reinterpret_cast<short*>(cbuffer));
    } else {
        benchmark_kernel<short, false, 0, 1, 1><<<blocks, threads>>>(seed, reinterpret_cast<short*>(cbuffer));
    }
}

static void runbench(const int compute_iterations_arr[],
                     unsigned int krn_idx,
                     void* cbuffer,
                     long size,
                     size_t workgroupsize,
                     unsigned int elements_per_wi,
                     unsigned int fusion_degree,
                     bool use_os_timer,
                     bool block_strided,
                     bool enable_dp,
                     bool enable_hp) {
    const long compute_grid_size = size / elements_per_wi / fusion_degree;
    const int current_compute_iterations = compute_iterations_arr[krn_idx];
    const long long computations =
        (elements_per_wi * (long long)compute_grid_size +
         (2 * elements_per_wi * current_compute_iterations) * (long long)compute_grid_size) *
        fusion_degree;
    const long long memoryoperations = size;

    const int threads = static_cast<int>(workgroupsize);
    const int blocks = static_cast<int>(compute_grid_size / static_cast<long>(workgroupsize));

    constexpr int total_bench_iterations = 3;

    double kernel_time_mad_sp = benchmark_repeat<total_bench_iterations>([&]() {
        const float seed_f = 1.0f;
        return time_cuda_kernel([&]() {
            if (block_strided) {
                launch_benchmark_kernel<float, true, 8, 4>(
                    current_compute_iterations, blocks, threads, seed_f,
                    reinterpret_cast<float*>(cbuffer));
            } else {
                launch_benchmark_kernel<float, false, 8, 4>(
                    current_compute_iterations, blocks, threads, seed_f,
                    reinterpret_cast<float*>(cbuffer));
            }
        }, use_os_timer);
    });

    double kernel_time_mad_dp = benchmark_repeat<total_bench_iterations>([&]() {
        const double seed_d = 1.0;
        if (!enable_dp)
            return 0.0;
        return time_cuda_kernel([&]() {
            if (block_strided) {
                launch_benchmark_kernel<double, true, 8, 4>(
                    current_compute_iterations, blocks, threads, seed_d,
                    reinterpret_cast<double*>(cbuffer));
            } else {
                launch_benchmark_kernel<double, false, 8, 4>(
                    current_compute_iterations, blocks, threads, seed_d,
                    reinterpret_cast<double*>(cbuffer));
            }
        }, use_os_timer);
    });

    double kernel_time_mad_hp = benchmark_repeat<total_bench_iterations>([&]() {
        const __half2 seed_h = __float2half2_rn(1.0f);
        if (!enable_hp)
            return 0.0;
        return time_cuda_kernel([&]() {
            if (block_strided) {
                launch_benchmark_kernel<__half2, true, 8, 4>(
                    current_compute_iterations, blocks, threads, seed_h,
                    reinterpret_cast<__half2*>(cbuffer));
            } else {
                launch_benchmark_kernel<__half2, false, 8, 4>(
                    current_compute_iterations, blocks, threads, seed_h,
                    reinterpret_cast<__half2*>(cbuffer));
            }
        }, use_os_timer);
    });

    double kernel_time_mad_int = benchmark_repeat<total_bench_iterations>([&]() {
        const int seed_i = static_cast<int>(1.0);
        return time_cuda_kernel([&]() {
            if (block_strided) {
                launch_benchmark_kernel<int, true, 8, 4>(
                    current_compute_iterations, blocks, threads, seed_i,
                    reinterpret_cast<int*>(cbuffer));
            } else {
                launch_benchmark_kernel<int, false, 8, 4>(
                    current_compute_iterations, blocks, threads, seed_i,
                    reinterpret_cast<int*>(cbuffer));
            }
        }, use_os_timer);
    });

    printf(
        "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
        "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        current_compute_iterations,
        ((double)computations) / ((double)memoryoperations * sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations) / kernel_time_mad_sp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(double)),
        kernel_time_mad_dp,
        ((double)computations) / kernel_time_mad_dp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)2 * computations) /
            ((double)memoryoperations * sizeof(__half2)),
        kernel_time_mad_hp,
        ((double)2 * computations) / kernel_time_mad_hp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(__half2)) / kernel_time_mad_hp *
            1000. / (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(int)),
        kernel_time_mad_int,
        ((double)computations) / kernel_time_mad_int * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
            (1000. * 1000. * 1000.));
}

extern "C" void mixbenchGPU(double* c, long size) {
    const bool block_strided = false;
    const bool host_allocated = false;
    const bool use_os_timer = false;
    const size_t workgroupsize = 256;
    const unsigned int elements_per_wi = 8;
    const unsigned int fusion_degree = 4;

    const char* benchtype;
    if (block_strided)
        benchtype = "Workgroup";
    else
        benchtype = "NDRange";
    printf("Workitem stride:        %s\n", benchtype);

    const char* buffer_allocation =
        host_allocated ? "Host allocated" : "Device allocated";
    printf("Buffer allocation:      %s\n", buffer_allocation);
    printf("Timer:                  %s\n",
           use_os_timer ? "OS based" : "CL event based");

    const cudaDeviceProp deviceProp = GetDeviceProperties();
    const bool enable_dp = (deviceProp.major > 1) || (deviceProp.major == 1 && deviceProp.minor >= 3);
    if (!enable_dp)
        printf(
            "Warning:                Double precision computations are not "
            "supported\n");
    const bool enable_hp = IsFP16Supported();
    if (!enable_hp)
        printf(
            "Warning:                Half precision computations are not "
            "supported\n");

    void* c_buffer = nullptr;
    CUDA_SAFE_CALL(cudaMalloc(&c_buffer, size * sizeof(double)));

    CUDA_SAFE_CALL(cudaMemset(c_buffer, 0, size * sizeof(int)));

    printf("Loading kernel source file...\n");
    printf("Precompilation of kernels... ");
    show_progress_init(compute_iterations_len);
    for (int i = 0; i < compute_iterations_len; i++) {
        show_progress_step(0, '\\');
        show_progress_step(0, '|');
        if (enable_dp)
            show_progress_step(0, '/');
        if (enable_hp)
            show_progress_step(0, '-');
        show_progress_step(1, '>');
    }
    show_progress_done();

    runbench_warmup(c_buffer, size, workgroupsize, block_strided);

    CUDA_SAFE_CALL(cudaDeviceSynchronize());

    printf(
        "------------------------------------------------------------------------"
        "----- CSV data "
        "------------------------------------------------------------------------"
        "-----\n");
    printf(
        "Experiment ID, Single Precision ops,,,,              Double precision "
        "ops,,,,              Half precision ops,,,,                Integer "
        "operations,,, \n");
    printf(
        "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
        "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
        "Iops/byte, ex.time,   GIOPS, GB/sec\n");

    for (int i = 0; i < compute_iterations_len; i++)
        runbench(compute_iterations, i, c_buffer, size, workgroupsize,
                 elements_per_wi, fusion_degree, use_os_timer, block_strided,
                 enable_dp, enable_hp);

    printf(
        "------------------------------------------------------------------------"
        "------------------------------------------------------------------------"
        "--------------------\n");

    CUDA_SAFE_CALL(cudaMemcpy(c, c_buffer, size * sizeof(double), cudaMemcpyDeviceToHost));
    CUDA_SAFE_CALL(cudaFree(c_buffer));
}
